        return array(
            'symbol' => $this->safe_string($market, 'symbol'),
            'side' => $this->safe_string_lower($quote, 'action'),
            'value' => $this->safe_number($quote, 'value'),
            'shares' => $this->safe_number($quote, 'shares'),
            'sharesThreshold' => $this->safe_number($quote, 'shares_threshold'),
            'priceAverage' => $this->safe_number($quote, 'price_average'),
            'priceBefore' => $this->safe_number($quote, 'price_before'),
            'priceAfter' => $this->safe_number($quote, 'price_after'),
            'netAmount' => $this->safe_number($quote, 'net_amount'),
            'fees' => $this->safe_dict($quote, 'fees'),
            'calldata' => $this->safe_string($quote, 'calldata'),
            'info' => $quote,
        );
    }

    public function rlp_encode_bytes(string $hex): string {
        // RLP-encodes a single byte string ($hex without 0x) per the Ethereum RLP spec
        $byteLength = $this->parse_to_int(strlen($hex) / 2);
        if ($byteLength === 0) {
            return '80';
        }
        if (($byteLength === 1) && ($hex < '80')) {
            return $hex;
        }
        if ($byteLength < 56) {
            return $this->int_to_base16(128 . $byteLength) . $hex;
        }
        $lengthHex = $this->int_to_base16($byteLength);
        if ((strlen(fmod($lengthHex), 2)) !== 0) {
            $lengthHex = '0' . $lengthHex;
        }
        $lengthOfLength = $this->parse_to_int(strlen($lengthHex) / 2);
        return $this->int_to_base16(183 . $lengthOfLength) . $lengthHex . $hex;
    }

    public function rlp_encode_list(array $items): string {
        $concatenated = '';
        for ($i = 0; $i < count($items); $i++) {
            $concatenated = $concatenated . $items[$i];
        }
        $byteLength = $this->parse_to_int(strlen($concatenated) / 2);
        if ($byteLength < 56) {
            return $this->int_to_base16(192 . $byteLength) . $concatenated;
        }
        $lengthHex = $this->int_to_base16($byteLength);
        if ((strlen(fmod($lengthHex), 2)) !== 0) {
            $lengthHex = '0' . $lengthHex;
        }
        $lengthOfLength = $this->parse_to_int(strlen($lengthHex) / 2);
        return $this->int_to_base16(247 . $lengthOfLength) . $lengthHex . $concatenated;
    }

    public function int_to_rlp_hex(float $value): string {
        // an integer minimal big-endian byte $hex; 0 is the empty byte string
        if ($value === 0) {
            return '';
        }
        $hex = $this->int_to_base16($value);
        if ((strlen(fmod($hex), 2)) !== 0) {
            $hex = '0' . $hex;
        }
        return $hex;
    }

    public function hex_to_rlp_bytes(string $hexValue): string {
        // a hex value (e.g. an RPC result) big-endian byte hex; leading zero bytes
        // are stripped and 0 becomes the empty byte string (RLP integer encoding)
        $h = $this->remove0x_prefix($hexValue);
        $start = 0;
        $total = count($h);
        while (($start < $total) && (mb_substr($h, $start, $start + 1 - $start) === '0')) {
            $start = $start + 1;
        }
        $h = mb_substr($h, $start);
        if ($h === '') {
            return '';
        }
        if ((strlen(fmod($h), 2)) !== 0) {
            $h = '0' . $h;
        }
        return $h;
    }

    public function sign_evm_transaction(array $tx, string $privateKey): string {
        // builds and signs an EIP-1559 (type 0x02) transaction, returning the signed raw $tx hex.
        // $tx $fields (nonce/gas/fees/value) are hex strings; chainId is an int. Verified
        // byte-identical to ethers' serialization
        $accessList = $this->rlp_encode_list(array());
        $fields = array(
            $this->rlp_encode_bytes($this->int_to_rlp_hex($this->safe_integer($tx, 'chainId'))),
            $this->rlp_encode_bytes($this->hex_to_rlp_bytes($this->safe_string($tx, 'nonce'))),
            $this->rlp_encode_bytes($this->hex_to_rlp_bytes($this->safe_string($tx, 'maxPriorityFeePerGas'))),
            $this->rlp_encode_bytes($this->hex_to_rlp_bytes($this->safe_string($tx, 'maxFeePerGas'))),
            $this->rlp_encode_bytes($this->hex_to_rlp_bytes($this->safe_string($tx, 'gasLimit'))),
            $this->rlp_encode_bytes($this->remove0x_prefix($this->safe_string($tx, 'to'))),
            $this->rlp_encode_bytes($this->hex_to_rlp_bytes($this->safe_string($tx, 'value', '0x0'))),
            $this->rlp_encode_bytes($this->remove0x_prefix($this->safe_string($tx, 'data', '0x'))),
            $accessList,
        );
        $payload = '02' . $this->rlp_encode_list($fields);
        $hashHex = $this->hash($this->base16_to_binary($payload), 'keccak', 'hex');
        $signature = $this->ecdsa($hashHex, $this->remove0x_prefix($privateKey), 'secp256k1', null);
        $rHex = $this->safe_string($signature, 'r');
        $sHex = $this->safe_string($signature, 's');
        if ((strlen(fmod($rHex), 2)) !== 0) {
            $rHex = '0' . $rHex;
        }
        if ((strlen(fmod($sHex), 2)) !== 0) {
            $sHex = '0' . $sHex;
        }
        $yParity = $this->safe_integer($signature, 'v');
        $signedFields = array();
        for ($i = 0; $i < count($fields); $i++) {
            $signedFields[] = $fields[$i];
        }
        $signedFields[] = $this->rlp_encode_bytes($this->int_to_rlp_hex($yParity));
        $signedFields[] = $this->rlp_encode_bytes($rHex);
        $signedFields[] = $this->rlp_encode_bytes($sHex);
        return '0x02' . $this->rlp_encode_list($signedFields);
    }

    public function eth_rpc(string $rpcUrl, string $method, array $rpcParams) {
        return Async\async(function () use ($rpcUrl, $method, $rpcParams) {
            $payload = array( 'jsonrpc' => '2.0', 'id' => 1, 'method' => $method, 'params' => $rpcParams );
            $headers = array( 'Content-Type' => 'application/json' );
            $response = Async\await($this->fetch($rpcUrl, 'POST', $headers, $this->json($payload)));
            $rpcError = $this->safe_value($response, 'error');
            if ($rpcError !== null) {
                throw new ExchangeError($this->id . ' rpc ' . $method . ' error => ' . $this->json($rpcError));
            }
            return $this->safe_string($response, 'result');
        }) ();
    }

    public function pad_hex_address(string $address): string {
        // left-pads a 20-byte $address to a 32-byte ABI word (24 leading zero bytes)
        $stripped = $this->remove0x_prefix($address);
        return '000000000000000000000000' . $stripped;
    }

    public function send_evm_transaction(string $rpcUrl, string $networkId, string $fromAddress, string $to, string $value, string $data, string $gasLimit): PromiseInterface {
        return Async\async(function () use ($rpcUrl, $networkId, $fromAddress, $to, $value, $data, $gasLimit) {
            $nonce = Async\await($this->eth_rpc($rpcUrl, 'eth_getTransactionCount', array( $fromAddress, 'pending' )));
            $gasPrice = Async\await($this->eth_rpc($rpcUrl, 'eth_gasPrice', array()));
            $tx = array(
                'chainId' => $this->parse_to_int($networkId),
                'nonce' => $nonce,
                'maxPriorityFeePerGas' => $gasPrice,
                'maxFeePerGas' => $gasPrice,
                'gasLimit' => $gasLimit,
                'to' => $to,
                'value' => $value,
                'data' => $data,
            );
            $signed = $this->sign_evm_transaction($tx, $this->privateKey);
            return Async\await($this->eth_rpc($rpcUrl, 'eth_sendRawTransaction', array( $signed )));
        }) ();
    }

    public function wait_for_transaction_receipt(string $rpcUrl, string $txHash, $timeout = 60000): PromiseInterface {
        return Async\async(function () use ($rpcUrl, $txHash, $timeout) {
            $start = $this->milliseconds();
            while (($this->milliseconds() - $start) < $timeout) {
                $receipt = Async\await($this->eth_rpc($rpcUrl, 'eth_getTransactionReceipt', array( $txHash )));
                if (($receipt !== null) && ($receipt !== null)) {
                    return $receipt;
                }
                Async\await($this->sleep(2000));
            }
            throw new ExchangeError($this->id . ' transaction ' . $txHash . ' not mined within timeout');
        }) ();
    }

    public function ensure_erc20_allowance(string $rpcUrl, string $networkId, string $token, string $owner, string $spender): PromiseInterface {
        return Async\async(function () use ($rpcUrl, $networkId, $token, $owner, $spender) {
            // allowance($owner, $spender)
            $allowanceData = '0xdd62ed3e' . $this->pad_hex_address($owner) . $this->pad_hex_address($spender);
            $current = Async\await($this->eth_rpc($rpcUrl, 'eth_call', array( array( 'to' => $token, 'data' => $allowanceData ), 'latest' )));
            $trimmed = $this->hex_to_rlp_bytes($current);
            // a max-approved allowance is ~32 bytes (64 nibbles); anything much smaller needs (re)approval
            if (strlen($trimmed) >= 50) {
                return null;
            }
            // approve($spender, maxUint256)
            $maxUint = 'ffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff';
            $approveData = '0x095ea7b3' . $this->pad_hex_address($spender) . $maxUint;
            $approveHash = Async\await($this->send_evm_transaction($rpcUrl, $networkId, $owner, $token, '0x0', $approveData, '0x186a0'));
            Async\await($this->wait_for_transaction_receipt($rpcUrl, $approveHash));
            return null;
        }) ();
    }

    public function create_order(string $symbol, ?string $type, ?string $side, ?float $amount, ?float $price = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $type, $side, $amount, $price, $params) {
            /**
             * create a trade order. Myriad has two trading models => a gasless order book (CLOB) where an EIP-712 signed order is posted off-chain and settled by the operator, and an on-chain AMM. Order-book markets are used by default; the model can be forced via $params->tradingModel
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da8281e2bc49cf4914b07528
             *
             * @param {string} $symbol unified outcome $symbol or outcome id
             * @param {string} $type 'limit' or 'market' (order book); ignored by the AMM path
             * @param {string} $side 'buy' or 'sell'
             * @param {float} $amount number of outcome shares to trade (AMM 'buy' spends this value instead)
             * @param {float} [$price] $price per share fraction in [0, 1] (required for order-book limit orders)
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->tradingModel] 'ob' to force the order book, 'amm' to force the on-chain AMM; defaults to the market's model
             * @param {string} [$params->timeInForce] order-book time in force => 'GTC', 'GTD', 'FOK', 'FAK' or 'PO'
             * @param {string} [$params->expiration] unix-seconds expiration for a GTD order
             * @return {array} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $outcomeObj = $this->outcome ($symbol);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $defaultModel = $this->safe_string($info, 'tradingModel', 'amm');
            $tradingModel = $this->safe_string_lower($params, 'tradingModel', $defaultModel);
            $rest = $this->omit($params, array( 'tradingModel' ));
            if ($tradingModel === 'ob') {
                return Async\await($this->create_orderbook_order($symbol, $type, $side, $amount, $price, $rest));
            }
            return Async\await($this->create_amm_order($symbol, $type, $side, $amount, $price, $rest));
        }) ();
    }

    public function create_orderbook_order(string $symbol, ?string $type, ?string $side, ?float $amount, ?float $price = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $type, $side, $amount, $price, $params) {
            /**
             * @ignore
             * signs an EIP-712 $order and posts it to the gasless $order book; the operator settles the match on-chain
             * @return {array} an [$order structure](https://docs.ccxt.com/#/?id=$order-structure)
             */
            if ($this->privateKey === null) {
                throw new ArgumentsRequired($this->id . ' createOrder() requires a privateKey to sign the order');
            }
            $outcomeObj = $this->outcome ($symbol);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $networkId = $this->safe_string($info, 'networkId', $this->safe_string($this->options, 'defaultNetworkId', '56'));
            $marketId = $this->safe_string($info, 'marketId');
            $outcomeId = $this->safe_integer($info, 'outcomeId', 0);
            $trader = $this->eth_get_address_from_private_key($this->privateKey);
            $typeStr = ($type === null) ? 'limit' : strtolower($type);
            $sideStr = strtolower($side);
            $sideInt = ($sideStr === 'buy') ? 0 : 1;
            $isMarket = ($typeStr === 'market');
            $defaultTif = $isMarket ? 'FOK' : 'GTC';
            $timeInForce = $this->safe_string_upper($params, 'timeInForce', $defaultTif);
            $priceValue = $price;
            if ($priceValue === null) {
                if ($isMarket) {
                    $priceValue = ($sideInt === 0) ? 1 : 0;
                } else {
                    throw new ArgumentsRequired($this->id . ' createOrder() requires a $price for limit orders');
                }
            }
            $priceWei = $this->to_orderbook_wei($priceValue);
            if (Precise::string_lt($priceWei, '1')) {
                $priceWei = '1';
            }
            $amountWei = $this->to_orderbook_wei($amount);
            $nonce = $this->safe_string($params, 'nonce', $this->number_to_string($this->milliseconds()));
            $expiration = $this->safe_string($params, 'expiration', '0');
            $minFillAmount = $this->safe_string($params, 'minFillAmount', '0');
            $order = array(
                'trader' => $trader,
                'marketId' => $marketId,
                'outcomeId' => $outcomeId,
                'side' => $sideInt,
                'amount' => $amountWei,
                'price' => $priceWei,
                'minFillAmount' => $minFillAmount,
                'nonce' => $nonce,
                'expiration' => $expiration,
            );
            $signature = $this->sign_clob_order($order, $networkId);
            $request = array(
                'order' => $order,
                'signature' => $signature,
                'network_id' => $this->parse_to_int($networkId),
                'time_in_force' => $timeInForce,
            );
            $response = Async\await($this->myriadPublicPostOrders ($request));
            $wrapper = $this->extend($response, array( 'order' => $order, 'networkId' => $networkId, 'timeInForce' => $timeInForce ));
            return $this->parse_order($wrapper, $outcomeObj);
        }) ();
    }

    public function create_amm_order(string $symbol, ?string $type, ?string $side, ?float $amount, ?float $price = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $type, $side, $amount, $price, $params) {
            /**
             * @ignore
             * buys or sells outcome shares by submitting the quote's $calldata on-chain AMM transaction. Requires a privateKey with gas . collateral on the market's network
             * @return {array} an [order structure](https://docs.ccxt.com/#/?id=order-structure)
             */
            if ($this->privateKey === null) {
                throw new ArgumentsRequired($this->id . ' createOrder() requires a privateKey to sign the on-chain transaction');
            }
            $this->checkEventsAndMarkets ($symbol);
            $outcomeObj = $this->outcome ($symbol);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $networkId = $this->safe_string($info, 'networkId');
            $chains = $this->safe_dict($this->options, 'chains', array());
            $chainConfig = $this->safe_dict($chains, $networkId);
            if ($chainConfig === null) {
                throw new NotSupported($this->id . ' createOrder() has no on-chain config for network ' . $networkId);
            }
            $rpcUrl = $this->safe_string_2($params, 'rpcUrl', 'rpc', $this->safe_string($chainConfig, 'rpcUrl'));
            $predictionMarket = $this->safe_string($chainConfig, 'predictionMarket');
            $tokenAddress = $this->safe_string_2($params, 'token', 'tokenAddress', $this->safe_string($info, 'tokenAddress'));
            $gasLimit = $this->safe_string($params, 'gasLimit', '0xaae60');
            $sideStr = strtolower($side);
            $quoteParams = $this->omit($params, array( 'rpcUrl', 'rpc', 'token', 'tokenAddress', 'gasLimit' ));
            $quote = Async\await($this->fetch_trade_quote($symbol, $sideStr, $amount, $quoteParams));
            $calldata = $this->safe_string($this->safe_dict($quote, 'info', array()), 'calldata');
            $fromAddress = $this->eth_get_address_from_private_key($this->privateKey);
            // a buy spends the collateral token, so the prediction-market contract must be approved first
            if (($sideStr === 'buy') && ($tokenAddress !== null)) {
                Async\await($this->ensure_erc20_allowance($rpcUrl, $networkId, $tokenAddress, $fromAddress, $predictionMarket));
            }
            $txHash = Async\await($this->send_evm_transaction($rpcUrl, $networkId, $fromAddress, $predictionMarket, '0x0', $calldata, $gasLimit));
            return $this->parse_trade_tx($txHash, $quote, $outcomeObj, $sideStr);
        }) ();
    }

    public function sign_orderbook_typed_data(array $types, array $message, string $networkId): string {
        /**
         * @ignore
         * EIP-712 signs an order-book typed-data $message with the wallet private key (returns a 65-byte 0x $signature)
         * @return {string} the hex $signature
         */
        $chains = $this->safe_dict($this->options, 'chains', array());
        $chainConfig = $this->safe_dict($chains, $networkId, array());
        $exchangeAddress = $this->safe_string($chainConfig, 'obExchangeAddress');
        if ($exchangeAddress === null) {
            throw new NotSupported($this->id . ' order book trading is not configured for network ' . $networkId);
        }
        $domainName = $this->safe_string($this->options, 'obDomainName', 'MyriadCTFExchange');
        $domainVersion = $this->safe_string($this->options, 'obDomainVersion', '1');
        $domain = array(
            'name' => $domainName,
            'version' => $domainVersion,
            'chainId' => $this->parse_to_int($networkId),
            'verifyingContract' => $exchangeAddress,
        );
        $encoded = $this->eth_encode_structured_data($domain, $types, $message);
        $digest = $this->hash($encoded, 'keccak', 'hex');
        $signature = $this->ecdsa($digest, $this->remove0x_prefix($this->privateKey), 'secp256k1', null);
        $rRaw = $signature['r'];
        $sRaw = $signature['s'];
        $r = str_pad($rRaw, 64, '0', STR_PAD_LEFT);
        $s = str_pad($sRaw, 64, '0', STR_PAD_LEFT);
        $v = $this->sum(27, $signature['v']);
        $sigHex = '0x' . $r . $s . $this->int_to_base16($v);
        return strtolower($sigHex);
    }

    public function sign_clob_order(array $message, string $networkId): string {
        /**
         * @ignore
         * EIP-712 signs the order-book Order struct
         * @return {string} the hex signature
         */
        $orderStruct = array(
            array( 'name' => 'trader', 'type' => 'address' ),
            array( 'name' => 'marketId', 'type' => 'uint256' ),
            array( 'name' => 'outcomeId', 'type' => 'uint8' ),
            array( 'name' => 'side', 'type' => 'uint8' ),
            array( 'name' => 'amount', 'type' => 'uint256' ),
            array( 'name' => 'price', 'type' => 'uint256' ),
            array( 'name' => 'minFillAmount', 'type' => 'uint256' ),
            array( 'name' => 'nonce', 'type' => 'uint256' ),
            array( 'name' => 'expiration', 'type' => 'uint256' ),
        );
        return $this->sign_orderbook_typed_data(array( 'Order' => $orderStruct ), $message, $networkId);
    }

    public function sign_cancel_all(array $message, string $networkId): string {
        /**
         * @ignore
         * EIP-712 signs the order-book CancelAll struct
         * @return {string} the hex signature
         */
        $cancelStruct = array(
            array( 'name' => 'trader', 'type' => 'address' ),
            array( 'name' => 'marketId', 'type' => 'uint256' ),
            array( 'name' => 'timestamp', 'type' => 'uint256' ),
        );
        return $this->sign_orderbook_typed_data(array( 'CancelAll' => $cancelStruct ), $message, $networkId);
    }

    public function clob_order_message(array $rawOrder): array {
        /**
         * @ignore
         * normalises a fetched order-book order into a typed-data message (uint256 fields, uint8 fields)
         * @return {array} the typed-data message
         */
        return array(
            'trader' => $this->safe_string($rawOrder, 'trader'),
            'marketId' => $this->safe_string($rawOrder, 'marketId'),
            'outcomeId' => $this->safe_integer($rawOrder, 'outcomeId', 0),
            'side' => $this->safe_integer($rawOrder, 'side', 0),
            'amount' => $this->safe_string($rawOrder, 'amount'),
            'price' => $this->safe_string($rawOrder, 'price'),
            'minFillAmount' => $this->safe_string($rawOrder, 'minFillAmount', '0'),
            'nonce' => $this->safe_string($rawOrder, 'nonce'),
            'expiration' => $this->safe_string($rawOrder, 'expiration', '0'),
        );
    }

    public function to_orderbook_wei(?float $value): string {
        /**
         * @ignore
         * scales a decimal $value by 1e18 and truncates to an integer wei string
         * @return {string} the integer wei string
         */
        $valueStr = $this->number_to_string($value);
        $scaled = Precise::string_mul($valueStr, '1000000000000000000');
        // use > -1 (not >= 0) => when '.' is absent PHP's mb_strpos returns false, and false >= 0
        // coerces to true (wrongly truncating to empty), whereas false > -1 correctly coerces to false
        $dotIndex = mb_strpos($scaled, '.');
        if ($dotIndex > -1) {
            return mb_substr($scaled, 0, $dotIndex - 0);
        }
        return $scaled;
    }

    public function parse_order_status(?string $status): ?string {
        $statuses = array(
            'open' => 'open',
            'pending' => 'open',
            'partially_filled' => 'open',
            'filled' => 'closed',
            'cancelled' => 'canceled',
            'canceled' => 'canceled',
            'expired' => 'expired',
        );
        return $this->safe_string($statuses, $status, $status);
    }

    public function parse_order(array $order, ?array $market = null): array {
        $inner = $this->safe_dict($order, 'order', array());
        $orderHash = $this->safe_string_2($order, 'orderHash', 'hash');
        $sideInt = $this->safe_integer($inner, 'side');
        $side = ($sideInt === 1) ? 'sell' : 'buy';
        $amountWei = $this->safe_string($inner, 'amount');
        $priceWei = $this->safe_string($inner, 'price');
        $filledWei = $this->safe_string($order, 'filledAmount');
        $amount = ($amountWei === null) ? null : $this->parse_number(Precise::string_div($amountWei, '1000000000000000000'));
        $price = ($priceWei === null) ? null : $this->parse_number(Precise::string_div($priceWei, '1000000000000000000'));
        $filled = ($filledWei === null) ? null : $this->parse_number(Precise::string_div($filledWei, '1000000000000000000'));
        $statusRaw = $this->safe_string_lower($order, 'status');
        $status = $this->parse_order_status($statusRaw);
        $timestamp = $this->parse8601($this->safe_string($order, 'createdAt'));
        $tif = $this->safe_string_upper($order, 'timeInForce');
        $isMarketTif = ($tif === 'FOK') || ($tif === 'FAK');
        $symbol = ($market === null) ? null : $this->safe_string($market, 'symbol');
        return $this->safe_order(array(
            'id' => $orderHash,
            'clientOrderId' => null,
            'info' => $order,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'lastTradeTimestamp' => null,
            'symbol' => $symbol,
            'type' => $isMarketTif ? 'market' : 'limit',
            'timeInForce' => $tif,
            'postOnly' => ($tif === 'PO'),
            'side' => $side,
            'price' => $price,
            'triggerPrice' => null,
            'amount' => $amount,
            'filled' => $filled,
            'remaining' => null,
            'cost' => null,
            'average' => null,
            'status' => $status,
            'fee' => null,
            'trades' => null,
        ), $market);
    }

    public function cancel_order(string $id, ?string $symbol = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($id, $symbol, $params) {
            /**
             * cancels an open order book order by its hash (re-signs the original order to prove ownership; gasless)
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da8281b58c5adb2f5998eec8
             *
             * @param {string} $id the order hash returned by createOrder
             * @param {string} [$symbol] unified outcome $symbol the order belongs to
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} an [order structure](https://docs.ccxt.com/#/?$id=order-structure)
             */
            if ($this->privateKey === null) {
                throw new ArgumentsRequired($this->id . ' cancelOrder() requires a privateKey to sign the cancellation');
            }
            Async\await($this->load_markets());
            $fetched = Async\await($this->myriadPublicGetOrdersHash ($this->extend(array( 'hash' => $id ), $params)));
            $rawOrder = $this->safe_dict($fetched, 'order', array());
            $networkId = $this->safe_string_2($fetched, 'networkId', 'network_id', $this->safe_string($this->options, 'defaultNetworkId', '56'));
            $message = $this->clob_order_message($rawOrder);
            $signature = $this->sign_clob_order($message, $networkId);
            $request = array(
                'hash' => $id,
                'order' => $message,
                'signature' => $signature,
                'network_id' => $this->parse_to_int($networkId),
            );
            $response = Async\await($this->myriadPublicDeleteOrdersHash ($request));
            $status = $this->safe_string($response, 'status', 'canceled');
            $wrapper = $this->extend($fetched, array( 'status' => $status, 'networkId' => $networkId ));
            $market = null;
            if ($symbol !== null) {
                $this->ensure_outcomes_loaded();
                $market = $this->outcome ($symbol);
            }
            return $this->parse_order($wrapper, $market);
        }) ();
    }

    public function cancel_all_orders(?string $symbol = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $params) {
            /**
             * cancels all open order book orders for the wallet, optionally scoped to one market (gasless)
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da8281e7a14cd34e6a716761
             *
             * @param {string} [$symbol] unified outcome $symbol; when omitted cancels across all markets
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} the raw response with the count of cancelled orders
             */
            if ($this->privateKey === null) {
                throw new ArgumentsRequired($this->id . ' cancelAllOrders() requires a privateKey to sign the cancellation');
            }
            Async\await($this->load_markets());
            $trader = $this->eth_get_address_from_private_key($this->privateKey);
            $marketId = $this->safe_string($params, 'market_id', '0');
            $networkId = $this->safe_string($params, 'network_id', $this->safe_string($this->options, 'defaultNetworkId', '56'));
            if ($symbol !== null) {
                $this->ensure_outcomes_loaded();
                $outcomeObj = $this->outcome ($symbol);
                $info = $this->safe_dict($outcomeObj, 'info', array());
                $marketId = $this->safe_string($info, 'marketId', $marketId);
                $networkId = $this->safe_string($info, 'networkId', $networkId);
            }
            $timestamp = $this->number_to_string($this->seconds());
            $message = array(
                'trader' => $trader,
                'marketId' => $marketId,
                'timestamp' => $timestamp,
            );
            $signature = $this->sign_cancel_all($message, $networkId);
            $request = array(
                'trader' => $trader,
                'market_id' => $this->parse_to_int($marketId),
                'timestamp' => $timestamp,
                'signature' => $signature,
                'network_id' => $this->parse_to_int($networkId),
            );
            return Async\await($this->myriadPublicPostOrdersCancelAll ($request));
        }) ();
    }

    public function fetch_order(string $id, ?string $symbol = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($id, $symbol, $params) {
            /**
             * fetches a single order book order by its hash
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da828116b8a0d976baea1df0
             *
             * @param {string} $id the order hash
             * @param {string} [$symbol] unified outcome $symbol the order belongs to
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} an [order structure](https://docs.ccxt.com/#/?$id=order-structure)
             */
            Async\await($this->load_markets());
            $response = Async\await($this->myriadPublicGetOrdersHash ($this->extend(array( 'hash' => $id ), $params)));
            $market = null;
            if ($symbol !== null) {
                $this->ensure_outcomes_loaded();
                $market = $this->outcome ($symbol);
            }
            return $this->parse_order($response, $market);
        }) ();
    }

    public function fetch_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * fetches order book orders for the wallet (or any $trader passed via $params->trader)
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da828171a003cf996487d008
             *
             * @param {string} [$symbol] unified outcome $symbol to filter by
             * @param {int} [$since] timestamp in ms of the earliest order
             * @param {int} [$limit] the maximum number of orders to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->trader] wallet address to query (defaults to the configured wallet)
             * @param {string} [$params->status] 'open', 'filled', 'cancelled' or 'expired'
             * @return {array[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
             */
            Async\await($this->load_markets());
            $request = array();
            $trader = $this->safe_string($params, 'trader');
            if ($trader === null) {
                if ($this->privateKey !== null) {
                    $request['trader'] = $this->eth_get_address_from_private_key($this->privateKey);
                } elseif ($this->walletAddress !== null) {
                    $request['trader'] = $this->walletAddress;
                }
            }
            $market = null;
            if ($symbol !== null) {
                $this->ensure_outcomes_loaded();
                $outcomeObj = $this->outcome ($symbol);
                $market = $outcomeObj;
                $request['market_id'] = $this->safe_string($this->safe_dict($outcomeObj, 'info', array()), 'marketId');
            }
            if ($limit !== null) {
                $request['limit'] = $limit;
            }
            $response = Async\await($this->myriadPublicGetOrders ($this->extend($request, $params)));
            $data = $this->safe_list($response, 'data', array());
            return $this->parse_orders($data, $market, $since, $limit);
        }) ();
    }

    public function fetch_open_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * fetches open order book orders for the wallet
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da828171a003cf996487d008
             *
             * @param {string} [$symbol] unified outcome $symbol to filter by
             * @param {int} [$since] timestamp in ms of the earliest order
             * @param {int} [$limit] the maximum number of orders to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
             */
            $request = array(
                'status' => 'open',
            );
            return Async\await($this->fetch_orders($symbol, $since, $limit, $this->extend($request, $params)));
        }) ();
    }

    public function parse_trade_tx(string $txHash, array $quote, mixed $market, string $side): array {
        return $this->safe_order(array(
            'id' => $txHash,
            'clientOrderId' => null,
            'info' => $this->extend(array( 'transactionHash' => $txHash ), $this->safe_dict($quote, 'info', array())),
            'symbol' => $this->safe_string($market, 'symbol'),
            'type' => 'market',
            'side' => $side,
            'price' => $this->safe_number($quote, 'priceAverage'),
            'amount' => $this->safe_number($quote, 'shares'),
            'cost' => $this->safe_number($quote, 'value'),
