    public function parse_market_to_event(array $raw, mixed $market): mixed {
        /**
         * @ignore
         * wraps a parsed myriad $market into a unified event structure
         * @param {array} $raw the $raw myriad $market object
         * @param {array} $market the parsed ccxt $market
         * @return {array} an event structure
         */
        $slug = $this->safe_string($raw, 'slug', $this->safe_string($raw, 'id'));
        $state = $this->safe_string($raw, 'state', 'open');
        $endDate = $this->safe_string($raw, 'expiresAt');
        return array(
            'id' => $market['id'],
            'slug' => $slug,
            'symbol' => $market['symbol'],
            'title' => $this->safe_string_2($raw, 'title', 'shortName'),
            'description' => $this->safe_string($raw, 'description'),
            'markets' => array( $market ),
            'url' => null,
            'image' => $this->safe_string($raw, 'imageUrl'),
            'active' => ($state === 'open'),
            'resolved' => ($state === 'resolved'),
            'category' => null,
            'tags' => $this->safe_list($raw, 'topics'),
            'created' => $this->parse8601($this->safe_string($raw, 'publishedAt')),
            'createdDatetime' => $this->safe_string($raw, 'publishedAt'),
            'end' => ($endDate !== null) ? $this->parse8601($endDate) : null,
            'endDatetime' => $endDate,
            'lastUpdatedAt' => null,
            'resolutionSource' => $this->safe_string($raw, 'resolutionSource'),
            'info' => $raw,
        );
    }

    public function parse_myriad_market(array $raw, ?string $eventSlug = null): array {
        /**
         * @ignore
         * converts a single $raw myriad market into one ccxt market with a list of $outcome objects
         * @param {array} $raw the $raw myriad market object
         * @param {string} [$eventSlug] the $slug of the parent event
         * @return {array} a [market structure](https://docs.ccxt.com/#/?id=market-structure)
         */
        $networkId = $this->safe_string($raw, 'networkId');
        $marketId = $this->safe_string($raw, 'id');
        $slug = $this->safe_string($raw, 'slug', $marketId);
        $rawOutcomes = $this->safe_list($raw, 'outcomes', array());
        $endDate = $this->safe_string($raw, 'expiresAt');
        $state = $this->safe_string($raw, 'state', 'open');
        $active = $state === 'open';
        $volume24h = $this->safe_number($raw, 'volume24h');
        $slugBase = ($eventSlug !== null) ? $eventSlug : $networkId;
        $marketSymbol = $this->slugToMarketSymbol ($slugBase, $slug);
        // the collateral token (address . decimals) is per-market; carry it for on-chain trading
        $tokenObj = $this->safe_dict($raw, 'token', array());
        $tokenAddress = $this->safe_string($tokenObj, 'address');
        $tokenDecimals = $this->safe_integer($tokenObj, 'decimals', 18);
        $outcomes = array();
        for ($i = 0; $i < count($rawOutcomes); $i++) {
            $outcome = $this->safe_dict($rawOutcomes, $i, array());
            $outcomeId = $this->safe_string($outcome, 'outcomeId', $this->safe_string($outcome, 'id', (string) $i));
            $outcomeLabel = $this->safe_string($outcome, 'label', $this->safe_string($outcome, 'title', $outcomeId));
            $price = $this->safe_number($outcome, 'price');
            $outcomes[] = array(
                'id' => $networkId . ':' . $marketId . '/' . $outcomeId,
                'symbol' => $this->slugToOutcomeSymbol ($slugBase, $slug, $outcomeLabel),
                'marketSymbol' => $marketSymbol,
                'label' => $outcomeLabel,
                'active' => $active,
                'info' => array(
                    'networkId' => $networkId,
                    'marketId' => $marketId,
                    'slug' => $slug,
                    'outcomeId' => $outcomeId,
                    'outcomeLabel' => $outcomeLabel,
                    'outcomePrice' => $price,
                    'volume24h' => $volume24h,
                    'state' => $state,
                    'tradingModel' => $this->safe_string($raw, 'tradingModel', 'amm'),
                    'tokenAddress' => $tokenAddress,
                    'tokenDecimals' => $tokenDecimals,
                ),
            );
        }
        return array(
            'id' => $networkId . ':' . $marketId,
            'symbol' => $marketSymbol,
            'base' => $slug,
            'quote' => 'USDC',
            'settle' => null,
            'baseId' => $networkId . ':' . $marketId,
            'quoteId' => 'USDC',
            'settleId' => null,
            'type' => 'prediction',
            'spot' => false,
            'margin' => false,
            'swap' => false,
            'future' => false,
            'option' => false,
            'prediction' => true,
            'active' => $active,
            'contract' => false,
            'linear' => null,
            'inverse' => null,
            'contractSize' => null,
            'expiry' => $endDate ? $this->parse8601($endDate) : null,
            'expiryDatetime' => $endDate,
            'strike' => null,
            'optionType' => null,
            'taker' => 0.02,
            'maker' => 0.02,
            'percentage' => true,
            'tierBased' => false,
            'feeSide' => 'get',
            'precision' => array(
                'amount' => 0.01,
                'price' => 0.001,
            ),
            'limits' => array(
                'leverage' => array( 'min' => 1, 'max' => 1 ),
                'amount' => array( 'min' => 0, 'max' => null ),
                'price' => array( 'min' => 0.001, 'max' => 0.999 ),
                'cost' => array( 'min' => null, 'max' => null ),
            ),
            'outcomes' => $outcomes,
            'info' => $this->extend($raw, array(
                'networkId' => $networkId,
                'marketId' => $marketId,
                'slug' => $slug,
                'volume24h' => $volume24h,
                'state' => $state,
            )),
            'created' => null,
        );
    }

