            //         "bannerImageUrl" => "https://imagedelivery.net/YN1-rdnufJQJCgu3i1CbVw/255d431f-1bb4-4d90-032b-d1f7032e8000/public",
            //         "ogImageUrl" => "https://imagedelivery.net/YN1-rdnufJQJCgu3i1CbVw/d3d60089-3d08-45ac-aa9d-139156e3f900/public",
            //         "liquidity" => "2000",
            //         "liquidityPrice" => "0.29322839",
            //         "volume" => "11396.236893",
            //         "volume24h" => "500",
            //         "volumeNotional" => "14101.517862",
            //         "volumeNotional24h" => "525.779869",
            //         "users" => "124",
            //         "shares" => "4547.083096",
            //         "featured" => false,
            //         "featuredAt" => null,
            //         "inPlay" => false,
            //         "inPlayStartsAt" => null,
            //         "perpetual" => false,
            //         "moneyline" => false,
            //         "executionMode" => "0",
            //         "tradingModel" => "amm",
            //         "topHolders" => array(
            //             "0x8A611AEE71b6448a6F99B6001D1234d020f7d546",
            //             "0x2993249A3D107B759c886a4BD4e02B70d471eA9B"
            //         ),
            //         "outcomes" => [
            //             {
            //                 "id" => "0",
            //                 "title" => "Yes",
            //                 "shares" => "4232.024971",
            //                 "sharesHeld" => "138.741271",
            //                 "price" => "0.06928796",
            //                 "closingPrice" => null,
            //                 "priceChange24h" => "-0.20109988",
            //                 "imageUrl" => "https://cdn.polkamarkets.com/Qma9FAX15kHewT8vm61vykGA9bqQhNdDLvEbQWSp72i3PQ",
            //                 "holders" => "7",
            //                 "tokenId" => "1512",
            //                 "price_charts" => [Array]
            //             }
            //         ],
            //         "eventId" => null,
            //         "outcomeIndex" => null,
            //         "negRisk" => false,
            //         "externalSources" => array()
            //     }
            //
            $outcomes = $this->safe_list($response, 'outcomes', array());
            $price = null;
            for ($i = 0; $i < count($outcomes); $i++) {
                $o = $outcomes[$i];
                if ($this->safe_string($o, 'outcomeId', $this->safe_string($o, 'id')) === $outcomeId) {
                    $price = $this->safe_number($o, 'price');
                    break;
                }
            }
            $timestamp = $this->milliseconds();
            // AMM => synthesize a single bid/ask pair around the current implied $price, clamped into the valid (0, 1) range
            $bid = null;
            $ask = null;
            if ($price !== null) {
                if ($price > 0.001) {
                    $bid = $this->parse_number(Precise::string_sub($this->number_to_string($price), '0.001'));
                }
                if ($price < 0.999) {
                    $ask = $this->parse_number(Precise::string_add($this->number_to_string($price), '0.001'));
                }
            }
            // the synthetic size must be a parsed float, an int literal breaks the typed go wrapper conversion
            $synthSize = $this->parse_number('9999');
            $bids = array();
            if ($bid !== null) {
                $bids[] = array( $bid, $synthSize );
            }
            $asks = array();
            if ($ask !== null) {
                $asks[] = array( $ask, $synthSize );
            }
            return array(
                'symbol' => $this->safeOutcomeSymbol ($outcome, $outcomeObj),
                'bids' => $bids,
                'asks' => $asks,
                'timestamp' => $timestamp,
                'datetime' => $this->iso8601($timestamp),
                'nonce' => null,
            );
        }) ();
    }

    public function parse_wei_order_book(array $response, ?string $symbol): array {
        /**
         * @ignore
         * parses an order book whose price and amount levels are 1e18-scaled integer strings
         * @param {array} $response the raw orderbook $response with $bids and $asks arrays
         * @param {string} $symbol the unified outcome $symbol of the order book
         * @return {array} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
         */
        $rawBids = $this->safe_list($response, 'bids', array());
        $rawAsks = $this->safe_list($response, 'asks', array());
        $bids = array();
        for ($i = 0; $i < count($rawBids); $i++) {
            $row = $rawBids[$i];
            $rowPrice = Precise::string_div($this->safe_string($row, 0), '1000000000000000000');
            $rowAmount = Precise::string_div($this->safe_string($row, 1), '1000000000000000000');
            $bids[] = array( $this->parse_number($rowPrice), $this->parse_number($rowAmount) );
        }
        $asks = array();
        for ($i = 0; $i < count($rawAsks); $i++) {
            $row = $rawAsks[$i];
            $rowPrice = Precise::string_div($this->safe_string($row, 0), '1000000000000000000');
            $rowAmount = Precise::string_div($this->safe_string($row, 1), '1000000000000000000');
            $asks[] = array( $this->parse_number($rowPrice), $this->parse_number($rowAmount) );
        }
        $timestamp = $this->milliseconds();
        return array(
            'symbol' => $symbol,
            'bids' => $this->sort_by($bids, 0, true),
            'asks' => $this->sort_by($asks, 0),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'nonce' => null,
        );
    }

    public function fetch_ohlcv(string $symbol, $timeframe = '1d', ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $timeframe, $since, $limit, $params) {
            /**
             * fetches price history for an $outcome from the price_charts $bucket embedded in the market $response
             *
             * @see https://docs.myriad.markets/builders/myriad-api-reference
             *
             * @param {string} $symbol unified $outcome $symbol like TRUMP_WIN:YES or an $outcome id
             * @param {string} $timeframe mapped to the closest available $chart $bucket (24h, 7d or 30d)
             * @param {int} [$since] timestamp in ms of the earliest candle to fetch
             * @param {int} [$limit] the maximum number of candles to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {int[][]} a list of candles ordered, open, high, low, close, volume
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $outcomeObj = $this->outcome ($symbol);
            $outcomeInfo = $this->safe_dict($outcomeObj, 'info', array());
            $networkId = $this->safe_string($outcomeObj['info'], 'networkId');
            $marketId = $this->safe_string($outcomeObj['info'], 'marketId');
            $outcomeId = $this->safe_string($outcomeInfo, 'outcomeId', $this->safe_string($outcomeInfo, 'id'));
            $outcomeTitle = $this->safe_string($outcomeInfo, 'outcomeLabel', $this->safe_string($outcomeInfo, 'label', $this->safe_string($outcomeInfo, 'title')));
            $bucketKey = $this->safe_string($this->timeframes, $timeframe, '30d');
            $response = Async\await($this->myriadPublicGetMarketsId ($this->extend(array(
                'id' => $marketId,
                'network_id' => $networkId,
            ), $params)));
            //
            //     {
            //         "id" => "164",
            //         "networkId" => "2741",
            //         "slug" => "trump-out-as-president-2027",
            //         "title" => "Will Trump cease to be President before 2027?",
            //         "state" => "open",
            //         "outcomes" => array(
            //             {
            //                 "id" => "0",
            //                 "outcomeId" => "0",
            //                 "title" => "YES",
            //                 "label" => "YES",
            //                 "price" => 0.42,
            //                 "priceChange24h" => -0.02
            //             }
            //         ),
            //         "price_charts" => {
            //             "24h" => {
            //                 "timeframe" => "24h",
            //                 "prices" => array(
            //                     array(
            //                         "timestamp" => 1705318200,
            //                         "open" => 0.40,
            //                         "high" => 0.45,
            //                         "low" => 0.39,
            //                         "close" => 0.42,
            //                         "price" => 0.42,
            //                         "value" => 0.42
            //                     }
            //                 )
            //             ),
            //             "7d" => array(...),
            //             "30d" => array(...)
            //         }
            //     }
            //
            $outcomes = $this->safe_list($response, 'outcomes', array());
            $selectedOutcome = null;
            for ($i = 0; $i < count($outcomes); $i++) {
                $outcome = $outcomes[$i];
                $currentId = $this->safe_string($outcome, 'id', $this->safe_string($outcome, 'outcomeId'));
                $currentTitle = $this->safe_string($outcome, 'title', $this->safe_string($outcome, 'label'));
                if (($outcomeId !== null) && ($currentId === $outcomeId)) {
                    $selectedOutcome = $outcome;
                    break;
                }
                if (($selectedOutcome === null) && ($outcomeTitle !== null) && ($currentTitle === $outcomeTitle)) {
                    $selectedOutcome = $outcome;
                }
            }
            // price_charts is a list of array( $timeframe, prices ) buckets, with a dict variant on some deployments
            $chart = null;
            $chartsList = $this->safe_list($selectedOutcome, 'price_charts');
            if ($chartsList !== null) {
                for ($i = 0; $i < count($chartsList); $i++) {
                    $chartObj = $chartsList[$i];
                    if ($this->safe_string($chartObj, 'timeframe') === $bucketKey) {
                        $chart = $chartObj;
                        break;
                    }
                }
            } else {
                $chartsDict = $this->safe_dict($selectedOutcome, 'price_charts', array());
                $chart = $this->safe_value($chartsDict, $bucketKey);
            }
            $pointsList = $this->safe_list($chart, 'prices', $this->safe_list($chart, 'data', $chart));
            $points = ($pointsList !== null) ? $pointsList : array();
            $pointsLength = count($points);
            if ($pointsLength === 0) {
                $priceCharts = $this->safe_dict($response, 'price_charts', array());
                $bucket = $this->safe_value($priceCharts, $bucketKey, array());
                $points = $this->safe_list($bucket, $outcomeId, $this->safe_list($bucket, 'data', array()));
            }
            $usablePoints = array();
            for ($i = 0; $i < count($points); $i++) {
                $point = $points[$i];
                $pointOpen = $this->safe_number($point, 'open');
                $pointPrice = $this->safe_number($point, 'price', $this->safe_number($point, 'value'));
                $pointTs = $this->safe_integer($point, 'timestamp');
                if ((($pointOpen !== null) || ($pointPrice !== null)) && ($pointTs !== null)) {
                    $usablePoints[] = $point;
                }
            }
            return $this->parse_ohlcvs($usablePoints, $outcomeObj, $timeframe, $since, $limit);
        }) ();
    }

    public function parse_ohlcv($ohlcv, ?array $market = null): array {
        /**
         * @ignore
         * parses a single myriad $price chart data point into an $ohlcv tuple
         * @param {array} $ohlcv the raw $price chart data point
         * @param {array} [$market] the outcome object the candle belongs to
         * @return {int[]} a candle ordered, $open, $high, $low, $close, volume
         */
        //
        //     {
        //         "timestamp" => 1705318200,
        //         "open" => 0.40,
        //         "high" => 0.45,
        //         "low" => 0.39,
        //         "close" => 0.42,
        //         "price" => 0.42,
        //         "value" => 0.42
        //     }
        //
        $open = $this->safe_number($ohlcv, 'open');
        $high = $this->safe_number($ohlcv, 'high');
        $low = $this->safe_number($ohlcv, 'low');
        $close = $this->safe_number($ohlcv, 'close');
        $price = $this->safe_number($ohlcv, 'price', $this->safe_number($ohlcv, 'value'));  // fallback single-value tick
        return array(
            $this->safe_timestamp($ohlcv, 'timestamp'),
            ($open !== null) ? $open : $price,
            ($high !== null) ? $high : $price,
            ($low !== null) ? $low : $price,
            ($close !== null) ? $close : $price,
            0,   // price_charts endpoint has no volume
        );
    }

    public function fetch_tickers(?array $symbols = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbols, $params) {
            /**
             * fetches tickers for multiple outcomes, grouping requested outcomes by their parent market to fetch each market only once
             *
             * @see https://docs.myriad.markets/builders/myriad-api-reference
             *
             * @param {string[]} [$symbols] unified outcome $symbols, refreshes the markets listing and returns tickers for all outcomes when omitted
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a dictionary of [$ticker structures](https://docs.ccxt.com/#/?id=$ticker-structure) indexed by outcome symbol
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $result = array();
            if ($symbols === null) {
                $rawMarkets = Async\await($this->fetch_raw_markets_list($params));
                for ($i = 0; $i < count($rawMarkets); $i++) {
                    $raw = $rawMarkets[$i];
                    $m = $this->parse_myriad_market($raw);
                    $outcomesList = $this->safe_list($m, 'outcomes', array());
                    for ($j = 0; $j < count($outcomesList); $j++) {
                        $ticker = $this->parse_ticker($raw, $outcomesList[$j]);
                        $symbolKey = $this->safe_string($ticker, 'symbol');
                        if ($symbolKey !== null) {
                            $result[$symbolKey] = $ticker;
                        }
                    }
                }
                return $result;
            }
            // group target outcomes by their parent market to fetch each market only once
            $outcomesByMarket = array();
            $marketKeys = array();
            for ($i = 0; $i < count($symbols); $i++) {
                $outcomeObj = $this->outcome ($symbols[$i]);
                $info = $this->safe_dict($outcomeObj, 'info', array());
                $networkId = $this->safe_string($info, 'networkId');
                $marketId = $this->safe_string($info, 'marketId');
                $key = $networkId . ':' . $marketId;
                if (!(is_array($outcomesByMarket) && array_key_exists($key, $outcomesByMarket))) {
                    $outcomesByMarket[$key] = array();
                    $marketKeys[] = $key;
                }
                // reassign after push, plain mutation through a local is lost in transpiled php (arrays are value types there)
                $grouped = $outcomesByMarket[$key];
                $grouped[] = $outcomeObj;
                $outcomesByMarket[$key] = $grouped;
            }
            $promises = array();
            for ($i = 0; $i < count($marketKeys); $i++) {
                $key = $marketKeys[$i];
                $grouped = $outcomesByMarket[$key];
                $firstOutcome = $grouped[0];
                $info = $this->safe_dict($firstOutcome, 'info', array());
                $promises[] = $this->myriadPublicGetMarketsId ($this->extend(array(
                    'id' => $this->safe_string($info, 'marketId'),
                    'network_id' => $this->safe_string($info, 'networkId'),
                ), $params));
            }
            $responses = Async\await(Promise\all($promises));
            for ($i = 0; $i < count($marketKeys); $i++) {
                $key = $marketKeys[$i];
                $response = $responses[$i];
                $grouped = $outcomesByMarket[$key];
                for ($j = 0; $j < count($grouped); $j++) {
                    $outcomeObj = $grouped[$j];
                    $ticker = $this->parse_ticker($response, $outcomeObj);
                    $symbolKey = $this->safe_string($ticker, 'symbol');
                    if ($symbolKey !== null) {
                        $result[$symbolKey] = $ticker;
                    }
                }
            }
            return $result;
        }) ();
    }

    public function fetch_trades(string $symbol, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * fetches recent public $trades for a single outcome from the market $action feed
             *
             * @see https://docs.myriad.markets/builders/myriad-api-reference
             *
             * @param {string} $symbol unified outcome $symbol like TRUMP_WIN:YES or an outcome id
             * @param {int} [$since] timestamp in ms of the earliest trade to fetch
             * @param {int} [$limit] the maximum number of $trades to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of [trade structures](https://docs.ccxt.com/#/?id=public-$trades)
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $outcomeObj = $this->outcome ($symbol);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $networkId = $this->safe_string($info, 'networkId');
            $marketId = $this->safe_string($info, 'marketId');
            $outcomeId = $this->safe_string($info, 'outcomeId');
            $request = array(
                'id' => $marketId,
                'network_id' => $networkId,
            );
            if ($limit !== null) {
                $request['limit'] = $limit;
            }
            $response = Async\await($this->myriadPublicGetMarketsIdEvents ($this->extend($request, $params)));
            //
            //     {
            //         "data" => array(
            //             {
            //                 "user" => "0xAE7Bfff784EeEe7812D6527B72c77A7Ed773Ed9D",
            //                 "action" => "buy",
            //                 "marketTitle" => "BNB candles from 10:00 to 10:05 UTC",
            //                 "marketSlug" => "bnb-candles-from-10-00-to-10-05-utc",
            //                 "marketId" => 218,
            //                 "networkId" => 56,
            //                 "outcomeTitle" => "More Green",
            //                 "outcomeId" => 0,
            //                 "shares" => 500,
            //                 "value" => 500,
            //                 "timestamp" => 1761645928,
            //                 "blockNumber" => 66193433,
            //                 "token" => "0x55d398326f99059fF775485246999027B3197955",
            //                 "txId" => "0x3c81447bd6e5c4c80a6e1425383c0b044ddcb1525d09027c2b371ff84f9b9fa0"
            //             }
            //         )
            //     }
            //
            $rowsList = $this->safe_list($response, 'data', $response);
            $rows = ($rowsList !== null) ? $rowsList : array();
            $trades = array();
            for ($i = 0; $i < count($rows); $i++) {
                $row = $rows[$i];
                $action = $this->safe_string($row, 'action');
                if (($action !== 'buy') && ($action !== 'sell')) {
                    continue;
                }
                $rowOutcomeId = $this->safe_string($row, 'outcomeId');
                if (($outcomeId !== null) && ($rowOutcomeId !== $outcomeId)) {
                    continue;
                }
                $trades[] = $row;
            }
            return $this->parse_trades($trades, $outcomeObj, $since, $limit);
        }) ();
    }

    public function parse_trade(array $trade, ?array $market = null): array {
        /**
         * @ignore
         * parses a raw $market action feed row into a unified $trade object
         * @param {array} $trade the raw action feed row
         * @param {array} [$market] the outcome object the $trade belongs to
         * @return {array} a [$trade structure](https://docs.ccxt.com/#/?id=public-trades)
         */
        $timestamp = $this->safe_timestamp($trade, 'timestamp');
        $amountStr = $this->safe_string($trade, 'shares');
        $costStr = $this->safe_string($trade, 'value');
        $priceStr = null;
        if (($amountStr !== null) && ($costStr !== null) && !Precise::string_eq($amountStr, '0')) {
            $priceStr = Precise::string_div($costStr, $amountStr);
        }
        return $this->safe_trade(array(
            'id' => $this->safe_string($trade, 'txId'),
            'info' => $trade,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'symbol' => $this->safe_symbol(null, $market),
            'order' => null,
            'type' => null,
            'side' => $this->safe_string($trade, 'action'),
            'takerOrMaker' => 'taker',
            'price' => $this->parse_number($priceStr),
            'amount' => $this->parse_number($amountStr),
            'cost' => $this->parse_number($costStr),
            'fee' => null,
        ), $market);
    }

    public function fetch_events($params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * fetches prediction-market events matching the given search terms (or all open markets when omitted) and caches their markets and outcomes on the instance
             *
             * @see https://docs.myriad.markets/builders/myriad-api-reference
             *
             * @param {array} [$params] extra exchange-specific parameters
             * @param {string} [$params->query] a single search term; when omitted (and no $queries) returns the events cached by loadMarkets (capped by options.fetchMarketsLimit)
             * @param {string[]} [$params->queries] multiple search terms (alternative to query)
             * @param {int} [$params->limit] maximum number of markets per query, defaults to 50
             * @param {string} [$params->state] 'open', 'closed' or 'resolved', defaults to 'open'
             * @return {array[]} an array of event structures
             */
            $queries = $this->parseSearchQueries ($params);
            $rest = $this->omit($params, array( 'query', 'queries' ));
            $queriesLength = count($queries);
            if ($queriesLength === 0) {
                Async\await($this->load_markets());
                $this->populate_outcomes();
                return is_array($this->events) ? array_values($this->events) : array();
            }
            $rawMarkets = Async\await($this->fetch_raw_markets_by_search($queries, $rest));
            if (!$this->events) {
                $this->events = array();
            }
            if (!$this->markets) {
                $this->markets = $this->create_safe_dictionary();
            }
            $result = array();
            for ($i = 0; $i < count($rawMarkets); $i++) {
                $raw = $rawMarkets[$i];
                $m = $this->parse_myriad_market($raw);
                $this->markets[$m['symbol']] = $m;
                $ev = $this->parse_market_to_event($raw, $m);
                $evKey = $this->safe_string($ev, 'symbol');
                if ($evKey !== null) {
                    $this->events[$evKey] = $ev;
                    $result[] = $ev;
                }
            }
            $this->populate_outcomes();
            return $result;
        }) ();
    }

    public function ensure_outcomes_loaded() {
        /**
         * @ignore
         * rebuilds the outcome caches from the loaded markets when they are empty
         * @return {null}
         */
        if (($this->outcomes === null) || $this->is_empty($this->outcomes)) {
            $this->populate_outcomes();
        }
    }

    public function populate_outcomes() {
        /**
         * @ignore
         * rebuilds $this->outcomes and $this->outcomes_by_id from the outcomes of every loaded $market
         * @return {null}
         */
        $this->outcomes = array();
        $this->outcomes_by_id = array();
        $marketKeys = is_array($this->markets) ? array_keys($this->markets) : array();
        for ($i = 0; $i < count($marketKeys); $i++) {
            $market = $this->markets[$marketKeys[$i]];
            $outcomesList = $this->safe_list($market, 'outcomes', array());
            for ($j = 0; $j < count($outcomesList); $j++) {
                $oc = $outcomesList[$j];
                $ocSymbol = $this->safe_string($oc, 'symbol');
                if ($ocSymbol !== null) {
                    $this->outcomes[$ocSymbol] = $oc;
                }
                $ocId = $this->safe_string($oc, 'id');
                if ($ocId !== null) {
                    $this->outcomes_by_id[$ocId] = $oc;
                }
            }
        }
    }

    public function parse_event(array $rawEvent): mixed {
        /**
         * @ignore
         * parses a raw myriad question object into the unified event shape with a nested markets list
         * @param {array} $rawEvent the raw myriad question object
         * @return {array} an event structure
         */
        $questionSlug = $this->safe_string($rawEvent, 'slug', $this->safe_string($rawEvent, 'id'));
        $rawMarkets = $this->safe_list($rawEvent, 'markets', array());
        $marketsList = array();
        for ($i = 0; $i < count($rawMarkets); $i++) {
            $rawMarket = $rawMarkets[$i];
            $marketsList[] = $this->parse_myriad_market($rawMarket, $questionSlug);
        }
        $endDate = $this->safe_string($rawEvent, 'expiresAt', $this->safe_string($rawEvent, 'endDate'));
        return $this->extend($rawEvent, array(
            'id' => $this->safe_string($rawEvent, 'id'),
            'slug' => $questionSlug,
            'symbol' => $questionSlug ? $this->shortenSlug ($questionSlug) : null,
            'title' => $this->safe_string($rawEvent, 'title'),
            'description' => $this->safe_string($rawEvent, 'description'),
            'markets' => $marketsList,
            'url' => $this->safe_string($rawEvent, 'url'),
            'image' => $this->safe_string($rawEvent, 'imageUrl', $this->safe_string($rawEvent, 'image')),
            'active' => $this->safe_bool($rawEvent, 'active'),
            'resolved' => $this->safe_bool($rawEvent, 'resolved', false),
            'category' => $this->safe_string($rawEvent, 'category'),
            'tags' => $this->safe_list($rawEvent, 'tags'),
            'created' => $this->parse8601($this->safe_string($rawEvent, 'createdAt')),
            'createdDatetime' => $this->safe_string($rawEvent, 'createdAt'),
            'end' => $endDate ? $this->parse8601($endDate) : null,
            'endDatetime' => $endDate,
            'lastUpdatedAt' => $this->parse8601($this->safe_string($rawEvent, 'updatedAt')),
            'resolutionSource' => $this->safe_string($rawEvent, 'resolutionSource'),
            'info' => $rawEvent,
        ));
    }

    public function request_id(string $url): float {
        $existing = $this->safe_value($this->options, 'requestId');
        if ($existing === null) {
            $this->options['requestId'] = $this->create_safe_dictionary();
        }
        $options = $this->options['requestId'];
        $previousValue = $this->safe_integer($options, $url, 0);
        $newValue = $this->sum($previousValue, 1);
        $this->options['requestId'][$url] = $newValue;
        return $newValue;
    }

    public function from_wei(?string $wei): ?float {
        if ($wei === null) {
            return null;
        }
        return $this->parse_number(Precise::string_div($wei, '1000000000000000000'));
    }

    public function market_outcome_to_symbol(?string $networkId, ?string $marketId, ?string $outcomeId): ?string {
        $ocId = $networkId . ':' . $marketId . '/' . $outcomeId;
        $outcomeObj = $this->safe_dict($this->outcomes_by_id, $ocId);
        return $this->safe_string($outcomeObj, 'symbol');
    }

    public function connect_centrifugo(string $url): PromiseInterface {
        return Async\async(function () use ($url) {
            // Centrifugo requires an anonymous connect command before any subscribe. This sends it once per
            // connection and resolves when the connect reply arrives (see handleCentrifugoFrame). The base
            // clears $client->subscriptions on reconnect, so an absent 'connect' marker means a fresh handshake.
            $client = $this->client($url);
            $connectSent = $this->safe_value($client->subscriptions, 'connect');
            if ($connectSent === null) {
                $this->options['wsConnected'] = false;
                $requestId = $this->request_id($url);
                // give the anonymous connect a name so the params object is non-empty (PHP serialises an
                // empty array JSON array, which Centrifugo rejects)
                $connectMsg = array( 'connect' => array( 'name' => 'ccxt' ), 'id' => $requestId );
                return Async\await($this->watch($url, 'centrifugoConnected', $connectMsg, 'connect'));
            }
            if ($this->safe_bool($this->options, 'wsConnected', false)) {
                // the connect reply already arrived on this connection — safe to subscribe immediately
                return null;
            }
            // connect is in flight (sent by a concurrent subscribe) — wait on the shared reply future
            return Async\await($client->future ('centrifugoConnected'));
        }) ();
    }

    public function pong($client, $message = null) {
        return Async\async(function () use ($client, $message) {
            // Centrifugo server pings are empty frames; reply with the same empty frame to keep the link alive
            Async\await($client->send ('{}'));
        }) ();
    }

    public function subscribe_myriad_channel(string $messageHash, string $channel, $params = array ()): PromiseInterface {
        return Async\async(function () use ($messageHash, $channel, $params) {
            $url = $this->safe_string($this->urls['api'], 'ws');
            // finish the connect handshake first so the subscribe frame is sent after the connect reply
            Async\await($this->connect_centrifugo($url));
            $requestId = $this->request_id($url);
            $subscribeMsg = array( 'subscribe' => array( 'channel' => $channel ), 'id' => $requestId );
            return Async\await($this->watch($url, $messageHash, $subscribeMsg, $channel));
        }) ();
    }

    public function handle_message($client, $message) {
        // Centrifugo packs several commands per frame joined by \n; a multi-command frame fails the
        // base JSON.parse and arrives here raw string, a single command arrives already $parsed
        if (gettype($message) === 'string') {
            $lines = explode('\n', $message);
            $linesLength = count($lines);
            for ($i = 0; $i < $linesLength; $i++) {
                $line = $lines[$i];
                if (strlen($line) > 0) {
                    $parsed = json_decode($line, $as_associative_array = true);
                    $this->handle_centrifugo_frame($client, $parsed);
                }
            }
            return;
        }
        $this->handle_centrifugo_frame($client, $message);
    }

    public function handle_centrifugo_frame($client, $msg) {
        $keys = is_array($msg) ? array_keys($msg) : array();
        $keysLength = count($keys);
        if ($keysLength === 0) {
            $this->spawn(array($this, 'pong'), $client, $msg);
            return;
        }
        $connectReply = $this->safe_dict($msg, 'connect');
        if ($connectReply !== null) {
            // connect acknowledged — unblock connectCentrifugo so $channel subscribes can be sent
            $this->options['wsConnected'] = true;
            $client->resolve (true, 'centrifugoConnected');
            return;
        }
        $push = $this->safe_dict($msg, 'push');
        if ($push === null) {
            return;
        }
        $channel = $this->safe_string($push, 'channel');
        if ($channel === null) {
            return;
        }
        $pub = $this->safe_dict($push, 'pub', array());
        $data = $this->safe_dict($pub, 'data', array());
        $parts = explode(':', $channel);
        $channelType = $this->safe_string($parts, 0);
        if ($channelType === 'orderbook') {
            $this->handle_order_book($client, $data);
        } elseif ($channelType === 'trades') {
            $this->handle_trades($client, $data);
        } elseif ($channelType === 'prices') {
            $this->handle_ticker($client, $data);
        } elseif ($channelType === 'orders') {
            $this->handle_order($client, $data);
        } elseif ($channelType === 'positions') {
            $this->handle_position($client, $data);
        }
    }

    public function watch_order_book(string $symbol, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $limit, $params) {
            /**
             * streams the order book for an outcome over the Centrifugo websocket; the $channel is delta-only so the book is seeded from the REST snapshot
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
             *
             * @param {string} $symbol unified outcome $symbol
             * @param {int} [$limit] the maximum number of order book entries to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} an [order book structure](https://docs.ccxt.com/#/?id=order-book-structure)
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $outcomeObj = $this->outcome ($symbol);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $networkId = $this->safe_string($info, 'networkId');
            $marketId = $this->safe_string($info, 'marketId');
            $sym = $this->safeOutcomeSymbol ($symbol, $outcomeObj);
            $channel = 'orderbook:' . $networkId . ':' . $marketId;
            $messageHash = 'orderbook::' . $sym;
            if ($this->safe_value($this->orderbooks, $sym) === null) {
                Async\await($this->seed_order_book($symbol, $sym, $limit));
            }
            $orderbook = Async\await($this->subscribe_myriad_channel($messageHash, $channel, $params));
            return $orderbook->limit ();
        }) ();
    }

    public function seed_order_book(string $symbol, string $sym, ?int $limit = null) {
        return Async\async(function () use ($symbol, $sym, $limit) {
            // the order book channel streams deltas only, so seed the live book from the REST $snapshot
            $snapshot = Async\await($this->fetch_order_book($symbol, $limit));
            $orderbook = $this->order_book(array());
            $orderbook->reset ($snapshot);
            $this->orderbooks[$sym] = $orderbook;
        }) ();
    }

    public function handle_order_book($client, $data) {
        $networkId = $this->safe_string($data, 'networkId');
        $marketId = $this->safe_string($data, 'marketId');
        $ts = $this->safe_integer($data, 'ts');
        $changes = $this->safe_list($data, 'changes', array());
        $changesLength = count($changes);
        $updated = array();
        for ($i = 0; $i < $changesLength; $i++) {
            $change = $changes[$i];
            $outcomeId = $this->safe_string($change, 'outcome');
            $sym = $this->market_outcome_to_symbol($networkId, $marketId, $outcomeId);
            if ($sym === null) {
                continue;
            }
            if ($this->safe_value($this->orderbooks, $sym) === null) {
                continue;
            }
            $orderbook = $this->orderbooks[$sym];
            $price = $this->from_wei($this->safe_string($change, 'price'));
            $amount = $this->from_wei($this->safe_string($change, 'amount'));
            $sideStr = $this->safe_string($change, 'side');
            $bookSide = ($sideStr === 'bid') ? $orderbook['bids'] : $orderbook['asks'];
            $bookSide->storeArray (array( $price, $amount ));
            $orderbook['timestamp'] = $ts;
            $orderbook['datetime'] = $this->iso8601($ts);
            $updated[$sym] = true;
        }
        $updatedSymbols = is_array($updated) ? array_keys($updated) : array();
        $updatedLength = count($updatedSymbols);
        for ($k = 0; $k < $updatedLength; $k++) {
            $sym = $updatedSymbols[$k];
            $client->resolve ($this->orderbooks[$sym], 'orderbook::' . $sym);
        }
    }

    public function watch_trades(string $symbol, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * streams public $trades for an outcome over the Centrifugo websocket
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
             *
             * @param {string} $symbol unified outcome $symbol
             * @param {int} [$since] timestamp in ms of the earliest trade
             * @param {int} [$limit] the maximum number of $trades to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of [trade structures](https://docs.ccxt.com/#/?id=public-$trades)
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $outcomeObj = $this->outcome ($symbol);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $networkId = $this->safe_string($info, 'networkId');
            $marketId = $this->safe_string($info, 'marketId');
            $sym = $this->safeOutcomeSymbol ($symbol, $outcomeObj);
            $channel = 'trades:' . $networkId . ':' . $marketId;
            $messageHash = 'trades::' . $sym;
            $trades = Async\await($this->subscribe_myriad_channel($messageHash, $channel, $params));
            return $this->filter_by_since_limit($trades, $since, $limit, 'timestamp', true);
        }) ();
    }

    public function handle_trades($client, $data) {
        $networkId = $this->safe_string($data, 'networkId');
        $marketId = $this->safe_string($data, 'marketId');
        $ts = $this->safe_integer($data, 'ts');
        $txHash = $this->safe_string($data, 'txHash');
        $taker = $this->safe_dict($data, 'taker', array());
        $outcomeId = $this->safe_string($taker, 'outcome');
        $sym = $this->market_outcome_to_symbol($networkId, $marketId, $outcomeId);
        if ($sym === null) {
            return;
        }
        $market = $this->safe_market($sym);
        // the trades channel reports human-decimal values (averagePrice "0.14", totalAmount "1"),
        // unlike the orders channel which is 1e18-scaled — so read them directly without fromWei
        $fees = $this->safe_dict($taker, 'totalFees', array());
        $trade = $this->safe_trade(array(
            'id' => $txHash,
            'info' => $data,
            'timestamp' => $ts,
            'datetime' => $this->iso8601($ts),
            'symbol' => $sym,
            'order' => $this->safe_string($taker, 'orderHash'),
            'type' => null,
            'side' => $this->safe_string_lower($taker, 'side'),
            'takerOrMaker' => 'taker',
            'price' => $this->safe_number($taker, 'averagePrice'),
            'amount' => $this->safe_number($taker, 'totalAmount'),
            'cost' => null,
            'fee' => array(
                'cost' => $this->safe_number($fees, 'total'),
                'currency' => $this->safe_string($market, 'quote'),
            ),
        ), $market);
        if ($this->trades === null) {
            $this->trades = $this->create_safe_dictionary();
        }
        if ($this->safe_value($this->trades, $sym) === null) {
            $tradesLimit = $this->safe_integer($this->options, 'tradesLimit', 1000);
            $this->trades[$sym] = new ArrayCache ($tradesLimit);
        }
        $stored = $this->trades[$sym];
        $stored->append ($trade);
        $client->resolve ($stored, 'trades::' . $sym);
    }

    public function watch_ticker(string $symbol, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $params) {
            /**
             * streams best bid/ask/last for an outcome over the Centrifugo prices $channel
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
             *
             * @param {string} $symbol unified outcome $symbol
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a [ticker structure](https://docs.ccxt.com/#/?id=ticker-structure)
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $outcomeObj = $this->outcome ($symbol);
            $info = $this->safe_dict($outcomeObj, 'info', array());
            $networkId = $this->safe_string($info, 'networkId');
            $marketId = $this->safe_string($info, 'marketId');
            $sym = $this->safeOutcomeSymbol ($symbol, $outcomeObj);
            $channel = 'prices:' . $networkId . ':' . $marketId;
            $messageHash = 'ticker::' . $sym;
            return Async\await($this->subscribe_myriad_channel($messageHash, $channel, $params));
        }) ();
    }

    public function handle_ticker($client, $data) {
        $networkId = $this->safe_string($data, 'networkId');
        $marketId = $this->safe_string($data, 'marketId');
        $ts = $this->safe_integer($data, 'ts');
        $outcomes = $this->safe_list($data, 'outcomes', array());
        $outcomesLength = count($outcomes);
        if ($this->tickers === null) {
            $this->tickers = $this->create_safe_dictionary();
        }
        for ($i = 0; $i < $outcomesLength; $i++) {
            $oc = $outcomes[$i];
            $outcomeId = $this->safe_string($oc, 'outcome');
            $sym = $this->market_outcome_to_symbol($networkId, $marketId, $outcomeId);
            if ($sym === null) {
                continue;
            }
            $market = $this->safe_market($sym);
            $last = $this->from_wei($this->safe_string($oc, 'last'));
            $ticker = $this->safe_ticker(array(
                'symbol' => $sym,
                'timestamp' => $ts,
                'datetime' => $this->iso8601($ts),
                'high' => null,
                'low' => null,
                'bid' => $this->from_wei($this->safe_string($oc, 'bestBid')),
                'bidVolume' => null,
                'ask' => $this->from_wei($this->safe_string($oc, 'bestAsk')),
                'askVolume' => null,
                'vwap' => null,
                'open' => null,
                'close' => $last,
                'last' => $last,
                'previousClose' => null,
                'change' => null,
                'percentage' => null,
                'average' => null,
                'baseVolume' => null,
                'quoteVolume' => null,
                'info' => $oc,
            ), $market);
            $this->tickers[$sym] = $ticker;
            $client->resolve ($ticker, 'ticker::' . $sym);
        }
    }

    public function watch_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * streams the wallet's order lifecycle updates over the Centrifugo $orders $channel
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
             *
             * @param {string} [$symbol] unified outcome $symbol to filter by
             * @param {int} [$since] timestamp in ms of the earliest order
             * @param {int} [$limit] the maximum number of $orders to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of [order structures](https://docs.ccxt.com/#/?id=order-structure)
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $trader = $this->wallet_address_from_keys();
            $networkId = $this->safe_string($this->options, 'defaultNetworkId', '56');
            if ($symbol !== null) {
                $outcomeObj = $this->outcome ($symbol);
                $info = $this->safe_dict($outcomeObj, 'info', array());
                $networkId = $this->safe_string($info, 'networkId', $networkId);
                $symbol = $this->safeOutcomeSymbol ($symbol, $outcomeObj);
            }
            $channel = 'orders:' . $networkId . ':' . $trader;
            $messageHash = 'orders';
            $orders = Async\await($this->subscribe_myriad_channel($messageHash, $channel, $params));
            return $this->filter_by_symbol_since_limit($orders, $symbol, $since, $limit, true);
        }) ();
    }

    public function handle_order($client, $data) {
        if ($this->orders === null) {
            $limit = $this->safe_integer($this->options, 'ordersLimit', 1000);
            $this->orders = new ArrayCacheBySymbolById ($limit);
        }
        $networkId = $this->safe_string($data, 'networkId');
        $marketId = $this->safe_string($data, 'marketId');
        $outcomeId = $this->safe_string($data, 'outcome');
        $sym = $this->market_outcome_to_symbol($networkId, $marketId, $outcomeId);
        $price = $this->from_wei($this->safe_string($data, 'price'));
        $amount = $this->from_wei($this->safe_string($data, 'amount'));
        $filled = $this->from_wei($this->safe_string($data, 'filledAmount'));
        $status = $this->parse_order_status($this->safe_string_lower($data, 'status'));
        $tif = $this->safe_string_upper($data, 'timeInForce');
        $isMarketTif = ($tif === 'FOK') || ($tif === 'FAK');
        $timestamp = $this->parse8601($this->safe_string_2($data, 'updatedAt', 'createdAt'));
        $parsed = $this->safe_order(array(
            'id' => $this->safe_string($data, 'orderHash'),
            'clientOrderId' => null,
            'info' => $data,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'symbol' => $sym,
            'type' => $isMarketTif ? 'market' : 'limit',
            'timeInForce' => $tif,
            'side' => $this->safe_string_lower($data, 'side'),
            'price' => $price,
            'amount' => $amount,
            'filled' => $filled,
            'remaining' => null,
            'average' => null,
            'cost' => null,
            'status' => $status,
            'fee' => null,
            'trades' => null,
        ));
        $stored = $this->orders;
        $stored->append ($parsed);
        $client->resolve ($stored, 'orders');
        if ($sym !== null) {
            $client->resolve ($stored, 'orders::' . $sym);
        }
    }

    public function watch_positions(?array $symbols = null, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbols, $since, $limit, $params) {
            /**
             * streams the wallet's share-balance changes over the Centrifugo $positions $channel
             *
             * @see https://docs.myriad.markets/builders/myriad-order-book/order-book-api#37dc9e49da82810581f8d2c8be2364fa
             *
             * @param {string[]} [$symbols] unified outcome $symbols to filter by
             * @param {int} [$since] timestamp in ms of the earliest position update
             * @param {int} [$limit] the maximum number of position updates to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array[]} a list of [position structures](https://docs.ccxt.com/#/?id=position-structure)
             */
            Async\await($this->load_markets());
            $this->ensure_outcomes_loaded();
            $trader = $this->wallet_address_from_keys();
            $networkId = $this->safe_string($this->options, 'defaultNetworkId', '56');
            $channel = 'positions:' . $networkId . ':' . $trader;
            $messageHash = 'positions';
            $positions = Async\await($this->subscribe_myriad_channel($messageHash, $channel, $params));
            if ($this->newUpdates) {
                return $positions;
            }
            return $this->filter_by_symbols_since_limit($positions, $symbols, $since, $limit, true);
        }) ();
    }

    public function handle_position($client, $data) {
        if ($this->positions === null) {
            $limit = $this->safe_integer($this->options, 'positionsLimit', 1000);
            $this->positions = new ArrayCacheBySymbolById ($limit);
        }
        $networkId = $this->safe_string($data, 'networkId');
        $marketId = $this->safe_string($data, 'marketId');
        $outcomeId = $this->safe_string($data, 'outcome');
        $sym = $this->market_outcome_to_symbol($networkId, $marketId, $outcomeId);
        $ts = $this->safe_integer($data, 'ts');
        // the positions channel emits a signed share delta per fill/redeem/split/merge; the absolute
        // $balance and entry price are not pushed (refetch via fetchPositions when the full state is needed)
        $balance = $this->from_wei($this->safe_string($data, 'balance'));
        $parsed = $this->safe_position(array(
            'info' => $data,
            'id' => $this->safe_string($data, 'txHash'),
            'symbol' => $sym,
            'timestamp' => $ts,
            'datetime' => $this->iso8601($ts),
            'side' => 'long',
            'contracts' => $balance,
            'entryPrice' => null,
            'markPrice' => null,
            'notional' => null,
            'collateral' => null,
            'unrealizedPnl' => null,
        ));
        $stored = $this->positions;
        $stored->append ($parsed);
        $client->resolve ($stored, 'positions');
    }

    public function wallet_address_from_keys(): string {
        // the orders/positions channels are keyed by the lowercase trader $address (Centrifugo channels
        // are case-sensitive); lowercase here so the channel matches regardless of the $address checksum.
        // check length too => an unset walletAddress is an empty string (not null) in some languages
        $address = $this->walletAddress;
        $hasWallet = ($address !== null) && (strlen($this->walletAddress) > 0);
        if (!$hasWallet) {
            if ($this->privateKey === null) {
                throw new ArgumentsRequired($this->id . ' requires a walletAddress or privateKey to watch private channels');
            }
            $address = $this->eth_get_address_from_private_key($this->privateKey);
        }
        return strtolower($address);
    }

    public function sign(mixed $path, mixed $api = 'myriad', $method = 'GET', $params = array (), mixed $headers = null, mixed $body = null) {
        /**
         * @ignore
         * builds the request $url and attaches the x-$api-key header for private endpoints
         * @param {string} $path the endpoint $path
         * @param {string|string[]} $api the $api group and access level
         * @param {string} $method the http $method
         * @param {array} $params the request parameters
         * @param {array} [$headers] request $headers
         * @param {string} [$body] the request $body
         * @return {array} a dict with $url, $method, $body and $headers
         */
        $apiGroup = gettype($api) === 'string' ? $api : $api[0];
        $baseUrls = $this->urls['api'];
        $baseUrl = $this->safe_string($baseUrls, $apiGroup, $baseUrls['myriad']);
        $url = $baseUrl . '/' . $this->implode_params($path, $params);
        $query = $this->omit($params, $this->extract_params($path));
        if ($method === 'GET') {
            $querystring = $this->urlencode($query);
            if ($querystring) {
                $url .= '?' . $querystring;
            }
        }
        $existingHeaders = ($headers !== null) ? $headers : array();
        $headers = $this->extend(array(
            'Accept' => 'application/json',
            'Content-Type' => 'application/json',
        ), $existingHeaders);
        // non-GET requests carry the $params JSON $body (public POSTs like markets/quote
        // included — the previous logic only sent a $body for authenticated requests)
        if ($method !== 'GET') {
            $queryKeys = is_array($query) ? array_keys($query) : array();
            $queryKeysLength = count($queryKeys);
            if ($queryKeysLength > 0) {
                $body = $this->json($query);
            }
        }
        if ($this->apiKey) {
            $headers = $this->extend($headers, array( 'x-$api-key' => $this->apiKey ));
        }
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }
}
